(1, 1, '2023-12-16 10:07:26', '2023-12-16 10:07:26', '<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->', 'Hello world!', '', 'draft', 'open', 'open', '', 'hello-world', '', '', '2024-02-10 01:11:30', '2024-02-09 17:11:30', '', 0, 'https://ccoms.ph/?p=1', 0, 'post', '', 1),
(2, 1, '2023-12-16 10:07:26', '2023-12-16 10:07:26', '<!-- wp:uagb/container {"block_id":"21624d5c","innerContentCustomWidthDesktop":1120,"minHeightDesktop":737,"topMarginDesktop":0,"bottomMarginDesktop":50,"leftMarginDesktop":0,"rightMarginDesktop":0,"marginLink":false,"variationSelected":true,"isBlockRootParent":true} -->\n<div class="wp-block-uagb-container uagb-block-21624d5c alignfull uagb-is-root-container"><div class="uagb-container-inner-blocks-wrap"><!-- wp:uagb/container {"block_id":"c9c21947","leftPaddingDesktop":30,"rightPaddingDesktop":30,"paddingLink":false,"topMarginDesktop":50,"bottomMarginDesktop":30,"leftMarginDesktop":0,"rightMarginDesktop":0,"marginLink":false,"widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-c9c21947"><!-- wp:uagb/advanced-heading {"block_id":"6db81c59","classMigrate":true,"headingAlign":"center","headFontFamily":"Sora","headFontWeight":"600","headTransform":"none","headLineHeightType":"px","headFontSize":26,"headLineHeight":42,"headLetterSpacing":1,"headLoadGoogleFonts":true} -->\n<div class="wp-block-uagb-advanced-heading uagb-block-6db81c59"><h2 class="uagb-heading-text">Discover Your Local SEO Edge with Us</h2></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:paragraph {"align":"center","style":{"typography":{"fontStyle":"normal","fontWeight":"200"}},"fontSize":"normal","fontFamily":"sora"} -->\n<p class="has-text-align-center has-sora-font-family has-normal-font-size" style="font-style:normal;font-weight:200">We''re not just any SEO agency. We''re your partners in transforming your local online presence. With over a decade of experience, we specialize in crafting bespoke SEO solutions that not only enhance your visibility but also significantly boost your leads, calls, and customer interactions — organically.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:uagb/container -->\n\n<!-- wp:uagb/container {"block_id":"e60a1819","innerContentCustomWidthDesktop":100,"innerContentCustomWidthType":"%","directionDesktop":"row","justifyContentDesktop":"space-between","leftPaddingDesktop":20,"rightPaddingDesktop":20,"paddingLink":false,"topMarginDesktop":0,"bottomMarginDesktop":0,"leftMarginDesktop":0,"rightMarginDesktop":0,"marginLink":false,"variationSelected":true,"columnGapDesktop":30,"isBlockRootParent":true} -->\n<div class="wp-block-uagb-container uagb-block-e60a1819 alignfull uagb-is-root-container"><div class="uagb-container-inner-blocks-wrap"><!-- wp:uagb/container {"block_id":"33acdd02","widthDesktop":40,"widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-33acdd02"><!-- wp:uagb/advanced-heading {"block_id":"21b4047e","classMigrate":true,"headingTag":"p","headFontFamily":"Sora","headFontWeight":"600","headTransform":"none","headLineHeightType":"px","headLineHeight":42,"headLetterSpacing":1,"headLoadGoogleFonts":true} -->\n<div class="wp-block-uagb-advanced-heading uagb-block-21b4047e"><p class="uagb-heading-text"><strong>Your Path to Local Dominance Begins here</strong></p></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:uagb/icon-list {"block_id":"140b8575","classMigrate":true,"childMigrate":true,"parentIcon":"","gap":24,"fontFamily":"Sora","fontWeight":"200","fontTransform":"none","loadGoogleFonts":true} -->\n<div class="wp-block-uagb-icon-list uagb-block-140b8575"><div class="uagb-icon-list__wrap"><!-- wp:uagb/icon-list-child {"block_id":"92958ff4","label":"\\u003cstrong\\u003ePersonalized Approach\\u003c/strong\\u003e: We understand that your business is unique. Our free SEO analysis is the first step towards a strategy that''s tailored just for you, reflecting our commitment to personalized service.","label_color":"","fromParentIcon":""} -->\n<div class="wp-block-uagb-icon-list-child uagb-block-92958ff4"><span class="uagb-icon-list__label"><strong>Personalized Approach</strong>: We understand that your business is unique. Our free SEO analysis is the first step towards a strategy that''s tailored just for you, reflecting our commitment to personalized service.</span></div>\n<!-- /wp:uagb/icon-list-child -->\n\n<!-- wp:uagb/icon-list-child {"block_id":"3abe92ba","label":"\\u003cstrong\\u003eTrusted Expertise\\u003c/strong\\u003e: Benefit from our extensive experience and proven track record. We''re dedicated to ethical practices that rebuild trust in SEO and deliver real results.","label_color":"","fromParentIcon":""} -->\n<div class="wp-block-uagb-icon-list-child uagb-block-3abe92ba"><span class="uagb-icon-list__label"><strong>Trusted Expertise</strong>: Benefit from our extensive experience and proven track record. We''re dedicated to ethical practices that rebuild trust in SEO and deliver real results.</span></div>\n<!-- /wp:uagb/icon-list-child -->\n\n<!-- wp:uagb/icon-list-child {"block_id":"36371789","label":"\\u003cstrong\\u003eBeyond Rankings\\u003c/strong\\u003e: For us, it''s not just about getting you to the top of search results. It''s about increasing your bottom line. Our strategies are designed to bring tangible business growth, from more calls and inquiries to increased foot traffic.","label_color":"","fromParentIcon":""} -->\n<div class="wp-block-uagb-icon-list-child uagb-block-36371789"><span class="uagb-icon-list__label"><strong>Beyond Rankings</strong>: For us, it''s not just about getting you to the top of search results. It''s about increasing your bottom line. Our strategies are designed to bring tangible business growth, from more calls and inquiries to increased foot traffic.</span></div>\n<!-- /wp:uagb/icon-list-child -->\n\n<!-- wp:uagb/icon-list-child {"block_id":"f5189788","label":"\\u003cstrong\\u003eCommitment to Transparency\\u003c/strong\\u003e: We believe in clear communication and honest advice. This free analysis is a glimpse into our transparent process, showing you exactly how we can help without any hidden agendas.","label_color":"","fromParentIcon":""} -->\n<div class="wp-block-uagb-icon-list-child uagb-block-f5189788"><span class="uagb-icon-list__label"><strong>Commitment to Transparency</strong>: We believe in clear communication and honest advice. This free analysis is a glimpse into our transparent process, showing you exactly how we can help without any hidden agendas.</span></div>\n<!-- /wp:uagb/icon-list-child --></div></div>\n<!-- /wp:uagb/icon-list -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontStyle":"normal","fontWeight":"200"}},"fontSize":"normal","fontFamily":"sora"} -->\n<p class="has-sora-font-family has-normal-font-size" style="font-style:normal;font-weight:200">Let Core Conversion be the catalyst for your local business''s growth. Fill out the form now and take the first step towards securing your place as a local market leader.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:uagb/container -->\n\n<!-- wp:uagb/container {"block_id":"6519a416","widthDesktop":50,"topMarginDesktop":0,"bottomMarginDesktop":0,"leftMarginDesktop":0,"rightMarginDesktop":0,"widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-6519a416"><!-- wp:uagb/forms {"block_id":"6ed51e9c","formPaddingTop":0,"formPaddingRight":0,"formPaddingBottom":0,"formPaddingLeft":0,"buttonAlign":"center","confirmationMessage":"Your request is in good hands! We''ve successfully received your information and are eager to assist you in enhancing your local SEO. Our team may contact you for additional details to ensure a comprehensive analysis. You''ll hear from us again once your personalized analysis is ready.","afterSubmitToEmail":"free-consultation","afterSubmitEmailSubject":"Free Analysis","submitBgType":"gradient","submitBgHoverType":"gradient","labelloadGoogleFonts":true,"labelFontFamily":"Roboto","inputborderStyle":"","inputborderColor":"","reCaptchaEnable":true,"reCaptchaType":"v3","fieldBorderTopWidth":1,"fieldBorderLeftWidth":1,"fieldBorderRightWidth":1,"fieldBorderBottomWidth":1,"fieldBorderTopLeftRadius":3,"fieldBorderTopRightRadius":3,"fieldBorderBottomLeftRadius":3,"fieldBorderBottomRightRadius":3,"fieldBorderStyle":"solid","fieldBorderColor":"#BDBDBD","checkBoxToggleBorderTopWidth":1,"checkBoxToggleBorderLeftWidth":1,"checkBoxToggleBorderRightWidth":1,"checkBoxToggleBorderBottomWidth":1,"checkBoxToggleBorderTopLeftRadius":3,"checkBoxToggleBorderTopRightRadius":3,"checkBoxToggleBorderBottomLeftRadius":3,"checkBoxToggleBorderBottomRightRadius":3,"checkBoxToggleBorderStyle":"solid","checkBoxToggleBorderColor":"#BDBDBD","btnBorderTopLeftRadius":5,"btnBorderTopRightRadius":5,"btnBorderBottomLeftRadius":5,"btnBorderBottomRightRadius":5,"btnBorderStyle":"none","gradientValue":"linear-gradient(90deg,rgba(14,237,181,0.59) 0%,rgba(2,113,217,0.51) 100%)","gradientHValue":"linear-gradient(90deg,rgba(2,113,217,0.51) 0%,rgba(14,237,181,0.59) 100%)","selectHGradient":"basic","variationSelected":true} -->\n<div class="wp-block-uagb-forms uagb-forms__outer-wrap uagb-block-6ed51e9c uagb-forms__medium-btn"><form class="uagb-forms-main-form" method="post" autocomplete="on" name="uagb-form-6ed51e9c"><!-- wp:uagb/forms-name {"block_id":"d54e1182","nameRequired":true,"name":"First Name","placeholder":"John","autocomplete":"given-name"} -->\n<div class="wp-block-uagb-forms-name uagb-forms-name-wrap uagb-forms-field-set uagb-block-d54e1182"><div class="uagb-forms-name-label required uagb-forms-input-label" id="d54e1182">First Name</div><input type="text" placeholder="John" required class="uagb-forms-name-input uagb-forms-input" name="d54e1182" autocomplete="given-name"/></div>\n<!-- /wp:uagb/forms-name -->\n\n<!-- wp:uagb/forms-name {"block_id":"4494832a","nameRequired":true,"name":"Last Name","placeholder":"Doe","autocomplete":"family-name"} -->\n<div class="wp-block-uagb-forms-name uagb-forms-name-wrap uagb-forms-field-set uagb-block-4494832a"><div class="uagb-forms-name-label required uagb-forms-input-label" id="4494832a">Last Name</div><input type="text" placeholder="Doe" required class="uagb-forms-name-input uagb-forms-input" name="4494832a" autocomplete="family-name"/></div>\n<!-- /wp:uagb