(8, 1, '2023-12-16 17:33:36', '2023-12-16 17:33:36', '<!-- wp:group {"tagName":"header","style":{"color":{"gradient":"linear-gradient(185deg,rgb(77,208,232) 0%,rgb(27,130,238) 47%,rgb(153,91,230) 99%)"}},"layout":{"type":"constrained","contentSize":"75%"}} -->\n<header class="wp-block-group has-background" style="background:linear-gradient(185deg,rgb(77,208,232) 0%,rgb(27,130,238) 47%,rgb(153,91,230) 99%)"><!-- wp:group {"style":{"spacing":{"padding":{"top":"var:preset|spacing|10","right":"0","left":"0","bottom":"var:preset|spacing|10"},"margin":{"top":"0","bottom":"0"}}},"layout":{"type":"flex","flexWrap":"nowrap","justifyContent":"space-between"}} -->\n<div class="wp-block-group" style="margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--10);padding-right:0;padding-bottom:var(--wp--preset--spacing--10);padding-left:0"><!-- wp:group {"layout":{"type":"flex","flexWrap":"nowrap"}} -->\n<div class="wp-block-group"><!-- wp:image {"id":7,"width":"147px","height":"auto","sizeSlug":"full","linkDestination":"custom"} -->\n<figure class="wp-block-image size-full is-resized"><a href="/"><img src="https://ccoms.ph/wp-content/uploads/2023/12/Logo-white-wd-hole.png" alt="" class="wp-image-7" style="width:147px;height:auto"/></a></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:navigation {"ref":4} /--></div>\n<!-- /wp:group --></header>\n<!-- /wp:group -->', 'Header', '', 'publish', 'closed', 'closed', '', 'header', '', '', '2023-12-20 20:33:06', '2023-12-20 20:33:06', '', 0, 'https://ccoms.ph/uncategorized/header/', 0, 'wp_template_part', '', 0);
