agb/container -->\n\n<!-- wp:uagb/container {"block_id":"4c0b07c8","widthDesktop":33.333333333333336} -->\n<div class="wp-block-uagb-container uagb-block-4c0b07c8"><!-- wp:group {"layout":{"type":"constrained"}} -->\n<div class="wp-block-group"><!-- wp:image {"align":"center","id":257,"width":"132px","height":"132px","scale":"cover","sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image aligncenter size-full is-resized"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon066.png" alt="" class="wp-image-257" style="object-fit:cover;width:132px;height:132px"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"textAlign":"center","level":3,"style":{"elements":{"link":{"color":{"text":"var:preset|color|white"}}},"typography":{"fontSize":"23px","fontStyle":"normal","fontWeight":"600"}},"textColor":"white"} -->\n<h3 class="wp-block-heading has-text-align-center has-white-color has-text-color has-link-color" style="font-size:23px;font-style:normal;font-weight:600">Our Vision</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center","style":{"typography":{"fontSize":"14px","fontStyle":"normal","fontWeight":"200"},"elements":{"link":{"color":{"text":"var:preset|color|white"}}}},"textColor":"white","fontFamily":"sora"} -->\n<p class="has-text-align-center has-white-color has-text-color has-link-color has-sora-font-family" style="font-size:14px;font-style:normal;font-weight:200">To be the beacon of trust and innovation in Local SEO, propelling businesses to their peak potential. We envision a digital marketplace where our clients lead and set benchmarks, powered by our strategic SEO support.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:uagb/container -->\n\n<!-- wp:uagb/container {"block_id":"70a29b4b","widthDesktop":33.333333333333336} -->\n<div class="wp-block-uagb-container uagb-block-70a29b4b"><!-- wp:group {"layout":{"type":"constrained"}} -->\n<div class="wp-block-group"><!-- wp:image {"align":"center","id":2