(139, 1, '2024-01-13 13:06:38', '2024-01-13 13:06:38', '/* Add your CSS code here.\r\n\r\nFor example:\r\n.example {\r\n    color: red;\r\n}\r\n\r\nFor brushing up on your CSS knowledge, check out http://www.w3schools.com/css/css_syntax.asp\r\n\r\nEnd of comment */ \r\n\r\n/* Add hover animation to the button */\r\n.wp-block-button__link.has-background.wp-element-button {\r\n    /* Define the initial position */\r\n    transform: translateY(0);\r\n    transition: transform 0.3s ease-in-out; /* Add a smooth transition */\r\n\r\n    /* Other button styles like background color, text color, etc. */\r\n    background-color: #007bff;\r\n    color: #fff;\r\n    padding: 10px 20px;\r\n    border: none;\r\n    cursor: pointer;\r\n}\r\n\r\n.wp-block-button__link.has-background.wp-element-button:hover {\r\n    /* Change the position on hover to push it up */\r\n    transform: translateY(-5px);\r\n}\r\n\r\n/* Initial style for accordion items */\r\n.accordion-item {\r\n    border: 1px solid #ccc;\r\n    margin-bottom: 10px;\r\n}\r\n\r\n/* Style for accordion headers */\r\n.accordion-header {\r\n    cursor: pointer;\r\n    background-color: #f0f0f0;\r\n    padding: 10px;\r\n    margin: 0;\r\n}\r\n\r\n/* Style for hidden content */\r\n.accordion-content {\r\n    display: none;\r\n    padding: 10px;\r\n}\r\n\r\n/* Style for active (open) accordion items */\r\n.accordion-item.active .accordion-content {\r\n    display: block;\r\n}\r\n', 'Btn Push Up Animation', '', 'publish', 'closed', 'closed', '', '139', '', '', '2024-01-13 14:23:36', '2024-01-13 14:23:36', '', 0, 'https://ccoms.ph/?post_type=custom-css-js&#038;p=139', 0, 'custom-css-js', '', 0),
