(191, 1, '2024-01-13 14:24:10', '2024-01-13 14:24:10', '/* Add your JavaScript code here.\r\n\r\nIf you are using the jQuery library, then don''t forget to wrap your code inside jQuery.ready() as follows:\r\n\r\njQuery(document).ready(function( $ ){\r\n    // Your code in here\r\n});\r\n\r\n--\r\n\r\nIf you want to link a JavaScript file that resides on another server (similar to\r\n<script src="https://example.com/your-js-file.js"></script>), then please use\r\nthe "Add HTML Code" page, as this is a HTML code that links a JavaScript file.\r\n\r\nEnd of comment */ \r\n\r\njQuery(document).ready(function($) {\r\n    $(''.accordion-header'').click(function() {\r\n        $(this).parent().toggleClass(''active'');\r\n    });\r\n});\r\n\r\n', 'Accordion', '', 'publish', 'closed', 'closed', '', 'accordion', '', '', '2024-01-13 14:24:10', '2024-01-13 14:24:10', '', 0, 'https://ccoms.ph/?post_type=custom-css-js&#038;p=191', 0, 'custom-css-js', '', 0);
