(229, 1, '2024-01-14 05:23:11', '2024-01-14 05:23:11', '<!-- wp:group {"style":{"spacing":{"margin":{"top":"0"},"padding":{"top":"100px","bottom":"100px"}},"color":{"background":"#f4f8fe"}},"layout":{"type":"constrained","contentSize":"80%","justifyContent":"center","wideSize":"100%"}} -->\n<div class="wp-block-group has-background" style="background-color:#f4f8fe;margin-top:0;padding-top:100px;padding-bottom:100px"><!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:heading {"level":1,"style":{"elements":{"link":{"color":{"text":"#333333"}}},"spacing":{"margin":{"bottom":"0px","top":"0"}},"color":{"text":"#333333"},"typography":{"textTransform":"uppercase","fontSize":"11px"}}} -->\n<h1 class="wp-block-heading has-text-color has-link-color" style="color:#333333;margin-top:0;margin-bottom:0px;font-size:11px;text-transform:uppercase">about us</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading {"level":1,"style":{"elements":{"link":{"color":{"text":"#333333"}}},"spacing":{"margin":{"bottom":"0px","top":"0"}},"color":{"text":"#333333"},"typography":{"textTransform":"capitalize","fontSize":"36px","fontStyle":"normal","fontWeight":"500"}}} -->\n<h1 class="wp-block-heading has-text-color has-link-color" style="color:#333333;margin-top:0;margin-bottom:0px;font-size:36px;font-style:normal;font-weight:500;text-transform:capitalize">Empowering Your Local Success: A Decade of Expert and Ethical SEO</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our mission is to amplify your local business reach, driving more foot traffic and enhancing digital connections through increased phone calls and contact form inquiries. Guided by a decade of SEO expertise and a commitment to ethical practices, our team’s dedication to ethical and transparent SEO ensures that your growth is our top priority.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {"layout":{"type":"flex","verticalAlignment":"top","justifyContent":"left","orientation":"vertical","flexWrap":"nowrap"},"fontSize":"x-small"} -->\n<div class="wp-block-buttons has-custom-font-size has-x-small-font-size"><!-- wp:button /--></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"id":140,"sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full"><img src="https://ccoms.ph/wp-content/uploads/2024/01/About-us-our-expertise.jpg" alt="" class="wp-image-140"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->', '2-column-contentL-imageR', '', 'publish', 'closed', 'closed', '', '2-column-content-l-image-r', '', '', '2024-01-14 05:29:06', '2024-01-14 05:29:06', '', 0, 'https://ccoms.ph/uncategorized/2-column-content-l-image-r/', 0, 'wp_template_part', '', 0),
