r -->\n\n<!-- wp:uagb/container {"block_id":"97d55ffb","widthDesktop":40,"widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-97d55ffb"><!-- wp:paragraph {"align":"center","style":{"layout":{"selfStretch":"fit","flexSize":null},"typography":{"fontStyle":"normal","fontWeight":"200"}},"textColor":"white","fontSize":"x-small","fontFamily":"sora"} -->\n<p class="has-text-align-center has-white-color has-text-color has-sora-font-family has-x-small-font-size" style="font-style:normal;font-weight:200"> Copyright © 2024 Core Conversion. All Rights Reserved</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:uagb/container --></div></div>\n<!-- /wp:uagb/container --></div></footer>\n<!-- /wp:uagb/container -->', 'Footer', '', 'publish', 'closed', 'closed', '', 'footer', '', '', '2024-01-29 15:24:49', '2024-01-29 07:24:49', '', 0, 'https://ccoms.ph/uncategorized/footer/', 0, 'wp_template_part', '', 0);
