(336, 1, '2024-01-14 14:11:26', '2024-01-14 14:11:26', '<!-- wp:group {"style":{"spacing":{"margin":{"top":"100px"},"padding":{"top":"100px","bottom":"50px"}},"color":{"background":"#f4f8fe"}},"layout":{"type":"constrained","contentSize":"80%","justifyContent":"center","wideSize":"100%"}} -->\n<div class="wp-block-group has-background" style="background-color:#f4f8fe;margin-top:100px;padding-top:100px;padding-bottom:50px"><!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:heading {"level":1,"style":{"elements":{"link":{"color":{"text":"#333333"}}},"spacing":{"margin":{"bottom":"0px","top":"0"}},"color":{"text":"#333333"},"typography":{"textTransform":"uppercase","fontSize":"11px"}}} -->\n<h1 class="wp-block-heading has-text-color has-link-color" style="color:#333333;margin-top:0;margin-bottom:0px;font-size:11px;text-transform:uppercase">about us</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading {"level":1,"style":{"elements":{"link":{"color":{"text":"#333333"}}},"spacing":{"margin":{"bottom":"0px","top":"0"}},"color":{"text":"#333333"},"typography":{"textTransform":"capitalize","fontSize":"36px","fontStyle":"normal","fontWeight":"500"}}} -->\n<h1 class="wp-block-heading has-text-color has-link-color" style="color:#333333;margin-top:0;margin-bottom:0px;font-size:36px;font-style:normal;font-weight:500;text-transform:capitalize">Empowering Your Local Success: A Decade of Expert and Ethical SEO</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our mission is to amplify your local business reach, driving more foot traffic and enhancing digital connections through increased phone calls and contact form inquiries. Guided by a decade of SEO expertise and a commitment to ethical practices, our team’s dedication to ethical and transparent SEO ensures that your growth is our top priority.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"id":188,"sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full"><img src="https://ccoms.ph/wp-content/uploads/2024/01/How-we-do-SEO-strategies-01.jpg" alt="" class="wp-image-188"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {"style":{"dimensions":{"minHeight":"478px"},"spacing":{"margin":{"top":"50px","bottom":"50px"}}},"layout":{"type":"constrained","contentSize":"80%","wideSize":"100%"}} -->\n<div class="wp-block-group" style="min-height:478px;margin-top:50px;margin-bottom:50px"><!-- wp:group {"style":{"background":{"backgroundImage":{"url":"https://ccoms.ph/wp-content/uploads/2024/01/Icon049.png","id":237,"source":"file","title":"Icon049"}},"border":{"width":"1px","radius":"15px"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group" style="border-width:1px;border-radius:15px"><!-- wp:columns {"style":{"spacing":{"padding":{"top":"50px","bottom":"50px","left":"50px","right":"50px"}}}} -->\n<div class="wp-block-columns" style="padding-top:50px;padding-right:50px;padding-bottom:50px;padding-left:50px"><!-- wp:column {"verticalAlignment":"center"} -->\n<div class="wp-block-column is-vertically-aligned-center"><!-- wp:group {"layout":{"type":"constrained"}} -->\n<div class="wp-block-group"><!-- wp:image {"align":"center","id":241,"width":"132px","height":"132px","scale":"cover","sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image aligncenter size-full is-resized"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon065.png" alt="" class="wp-image-241" style="object-fit:cover;width:132px;height:132px"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"textAlign":"center","level":3,"style":{"elements":{"link":{"color":{"text":"var:preset|color|white"}}},"typography":{"fontSize":"23px","fontStyle":"normal","fontWeight":"600"}},"textColor":"white"} -->\n<h3 class="wp-block-heading has-text-align-center has-white-color has-text-color has-link-color" style="font-size:23px;font-style:normal;font-weight:600">Our Mission</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center","style":{"typography":{"fontSize":"14px","fontStyle":"normal","fontWeight":"400"},"elements":{"link":{"color":{"text":"var:preset|color|white"}}}},"textColor":"white"} -->\n<p class="has-text-align-center has-white-color has-text-color has-link-color" style="font-size:14px;font-style:normal;font-weight:400">Core Conversion is founded on the principle of transforming local businesses into digital success stories. We are here to enhance your online reach, ensuring an uptick in foot traffic, phone calls, and contact form inquiries that drive your business forward.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"top"} -->\n<div class="wp-block-column is-vertically-aligned-top"><!-- wp:group {"layout":{"type":"constrained"}} -->\n<div class="wp-block-group"><!-- wp:image {"align":"center","id":257,"width":"132px","height":"132px","scale":"cover","sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image aligncenter size-full is-resized"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon066.png" alt="" class="wp-image-257" style="object-fit:cover;width:132px;height:132px"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"textAlign":"center","level":3,"style":{"elements":{"link":{"color":{"text":"var:preset|color|white"}}},"typography":{"fontSize":"23px","fontStyle":"normal","fontWeight":"600"}},"textColor":"white"} -->\n<h3 class="wp-block-heading has-text-align-center has-white-color has-text-color has-link-color" style="font-size:23px;font-style:normal;font-weight:600">Our Vision</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center","style":{"typography":{"fontSize":"14px","fontStyle":"normal","fontWeight":"400"},"elements":{"link":{"color":{"text":"var:preset|color|white"}}}},"textColor":"white"} -->\n<p class="has-text-align-center has-white-color has-text-color has-link-color" style="font-size:14px;font-style:normal;font-weight:400">To be the beacon of trust and innovation in Local SEO, propelling businesses to their peak potential. We envision a digital marketplace where our clients lead and set benchmarks, powered by our strategic SEO support.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"top"} -->\n<div class="wp-block-column is-vertically-aligned-top"><!-- wp:group {"layout":{"type":"constrained"}} -->\n<div class="wp-block-group"><!-- wp:image {"align":"center","id":241,"width":"132px","height":"132px","scale":"cover","sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image aligncenter size-full is-resized"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon065.png" alt="" class="wp-image-241" style="object-fit:cover;width:132px;height:132px"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {"textAlign":"center","level":3,"style":{"elements":{"link":{"color":{"text":"var:preset|color|white"}}},"typography":{"fontSize":"23px","fontStyle":"normal","fontWeight":"600"}},"textColor":"white"} -->\n<h3 class="wp-block-heading has-text-align-center has-white-color has-text-color has-link-color" style="font-size:23px;font-style:normal;font-weight:600">Our Values</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center","style":{"typography":{"fontSize":"14px","fontStyle":"normal","fontWeight":"400"},"elements":{"link":{"color":{"text":"var:preset|color|white"}}}},"textColor":"white"} -->\n<p class="has-text-align-center has-white-color has-text-color has-link-color" style="font-size:14px;font-style:normal;font-weight:400">At the heart of Core Conversion lie our core values – Client-Centric Service, Results-Driven Strategies, Ethical SEO Practices, Unwavering Transparency, and Universal Accessibility. We pledge to uphold these values as we pave the digital path for your business''s growth.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {"style":{"background":{"backgroundImage":{"url":"https://ccoms.ph/wp-content/uploads/2024/01/BG01.jpg","id":87,"source":"file","title":"BG01"}},"spacing":{"margin":{"top":"50px","bottom":"50px"},"padding":{"top":"100px","bottom":"100px"},"blockGap":"0px"}},"layout":{"type":"constrained","contentSize":"80%","wideSize":"100%"}} -->\n<div class="wp-block-group" style="margin-top:50px;margin-bottom:50px;padding-top:100px;padding-bottom:100px"><!-- wp:heading {"textAlign":"center","style":{"typography":{"textTransform":"capitalize","fontSize":"32px","fontStyle":"normal","fontWeight":"600"}}} -->\n<h2 class="wp-block-heading has-text-align-center" style="font-size:32px;font-style:normal;font-weight:600;text-transform:capitalize">why choose us</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {"textAlign":"center","level":3,"style":{"typography":{"textTransform":"capitalize","fontSize":"28px","fontStyle":"normal","fontWeight":"500"}}} -->\n<h3 class="wp-block-heading has-text-align-center" style="font-size:28px;font-style:normal;font-weight:500;text-transform:capitalize">Why Partner with Core Conversion?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:columns {"style":{"spacing":{"padding":{"top":"50px"}}}} -->\n<div class="wp-block-columns" style="padding-top:50px"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:group {"align":"wide","style":{"color":{"gradient":"linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%)"},"border":{"radius":"15px"},"dimensions":{"minHeight":"268px"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignwide has-background" style="border-radius:15px;background:linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%);min-height:268px"><!-- wp:media-text {"align":"wide","mediaId":263,"mediaLink":"https://ccoms.ph/icon070/","mediaType":"image","mediaWidth":31,"verticalAlignment":"center","imageFill":false,"focalPoint":{"x":1,"y":1}} -->\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center" style="grid-template-columns:31% auto"><figure class="wp-block-media-text__media"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon070.png" alt="" class="wp-image-263 size-full"/></figure><div class="wp-block-media-text__content"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"28px","fontStyle":"normal","fontWeight":"600"},"color":{"text":"#333333"}}} -->\n<h3 class="wp-block-heading has-text-color" style="color:#333333;font-size:28px;font-style:normal;font-weight:600">Transparent Tracking &amp; Reporting</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontSize":"16px","fontStyle":"normal","fontWeight":"500"},"color":{"text":"#333333"}}} -->\n<p class="has-text-color" style="color:#333333;font-size:16px;font-style:normal;font-weight:500">We believe in visibility, not just in search engines but also in our partnership. With Core Conversion, experience clear, actionable insights through comprehensive tracking and reporting.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:media-text --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:group {"align":"wide","style":{"color":{"gradient":"linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%)"},"border":{"radius":"15px"},"dimensions":{"minHeight":"268px"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignwide has-background" style="border-radius:15px;background:linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%);min-height:268px"><!-- wp:media-text {"align":"wide","mediaId":272,"mediaLink":"https://ccoms.ph/icon067/","mediaType":"image","mediaWidth":31,"verticalAlignment":"center","imageFill":false} -->\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center" style="grid-template-columns:31% auto"><figure class="wp-block-media-text__media"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon067.png" alt="" class="wp-image-272 size-full"/></figure><div class="wp-block-media-text__content"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"28px","fontStyle":"normal","fontWeight":"600"},"color":{"text":"#333333"}}} -->\n<h3 class="wp-block-heading has-text-color" style="color:#333333;font-size:28px;font-style:normal;font-weight:600">Over 10 Years Experience</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontSize":"16px","fontStyle":"normal","fontWeight":"500"},"color":{"text":"#333333"}}} -->\n<p class="has-text-color" style="color:#333333;font-size:16px;font-style:normal;font-weight:500">"Leverage over a decade of SEO mastery with Core Conversion. Our history is rich with success stories, reflecting our enduring commitment to service excellence.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:media-text --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {"style":{"spacing":{"padding":{"top":"50px"}}}} -->\n<div class="wp-block-columns" style="padding-top:50px"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:group {"align":"wide","style":{"color":{"gradient":"linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%)"},"border":{"radius":"15px"},"dimensions":{"minHeight":"268px"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignwide has-background" style="border-radius:15px;background:linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%);min-height:268px"><!-- wp:media-text {"align":"wide","mediaId":274,"mediaLink":"https://ccoms.ph/icon068/","mediaType":"image","mediaWidth":31,"verticalAlignment":"center","imageFill":false} -->\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center" style="grid-template-columns:31% auto"><figure class="wp-block-media-text__media"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon068.png" alt="" class="wp-image-274 size-full"/></figure><div class="wp-block-media-text__content"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"28px","fontStyle":"normal","fontWeight":"600"},"color":{"text":"#333333"}}} -->\n<h3 class="wp-block-heading has-text-color" style="color:#333333;font-size:28px;font-style:normal;font-weight:600">Experts Dedicated to Your Campaign</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontSize":"16px","fontStyle":"normal","fontWeight":"500"},"color":{"text":"#333333"}}} -->\n<p class="has-text-color" style="color:#333333;font-size:16px;font-style:normal;font-weight:500">Our team of SEO aficionados is dedicated to curating a bespoke Local SEO strategy for your business. Your success is the mission that drives us.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:media-text --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:group {"align":"wide","style":{"color":{"gradient":"linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%)"},"border":{"radius":"15px"},"dimensions":{"minHeight":"268px"}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group alignwide has-background" style="border-radius:15px;background:linear-gradient(103deg,rgb(255,255,255) 0%,rgba(207,207,207,0) 100%);min-height:268px"><!-- wp:media-text {"align":"wide","mediaId":275,"mediaLink":"https://ccoms.ph/icon069/","mediaType":"image","mediaWidth":31,"verticalAlignment":"center","imageFill":false} -->\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center" style="grid-template-columns:31% auto"><figure class="wp-block-media-text__media"><img src="https://ccoms.ph/wp-content/uploads/2024/01/Icon069.png" alt="" class="wp-image-275 size-full"/></figure><div class="wp-block-media-text__content"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"28px","fontStyle":"normal","fontWeight":"600"},"color":{"text":"#333333"}}} -->\n<h3 class="wp-block-heading has-text-color" style="color:#333333;font-size:28px;font-style:normal;font-weight:600">Over 300+ Active Customers</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontSize":"16px","fontStyle":"normal","fontWeight":"500"},"color":{"text":"#333333"}}} -->\n<p class="has-text-color" style="color:#333333;font-size:16px;font-style:normal;font-weight:500">Join a thriving community of over a hundred businesses that trust Core Conversion. Your journey to the top of search results begins with our expert team.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:media-text --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {"style":{"dimensions":{"minHeight":""},"spacing":{"margin":{"top":"0","bottom":"50px"},"padding":{"top":"0","bottom":"0"}}},"layout":{"type":"constrained","contentSize":"80%","wideSize":"100%","justifyContent":"center"}} -->\n<div class="wp-block-group" style="margin-top:0;margin-bottom:50px;padding-top:0;padding-bottom:0"><!-- wp:group {"style":{"background":{"backgroundImage":{"url":"https://ccoms.ph/wp-content/uploads/2024/01/BG01.jpg","id":87,"source":"file","title":"BG01"}},"dimensions":{"minHeight":"217px"},"border":{"radius":"15px"},"position":{"type":""},"spacing":{"padding":{"top":"0","bottom":"0"}}},"layout":{"type":"constrained"}} -->\n<div class="wp-block-group" style="border-radius:15px;min-height:217px;padding-top:0;padding-bottom:0"><!-- wp:columns {"verticalAlignment":"center","align":"wide","style":{"spacing":{"padding":{"top":"var:preset|spacing|x-large"}}}} -->\n<div class="wp-block-columns alignwide are-vertically-aligned-center" style="padding-top:var(--wp--preset--spacing--x-large)"><!-- wp:column {"verticalAlignment":"center","style":{"spacing":{"padding":{"left":"var:preset|spacing|large"}}}} -->\n<div class="wp-block-column is-vertically-aligned-center" style="padding-left:var(--wp--preset--spacing--large)"><!-- wp:heading {"textAlign":"center","style":{"elements":{"link":{"color":{"text":"var:preset|color|white"}}},"typography":{"fontSize":"35px","fontStyle":"normal","fontWeight":"400","lineHeight":"1.2"}},"textColor":"white"} -->\n<h2 class="wp-block-heading has-text-align-center has-white-color has-text-color has-link-color" style="font-size:35px;font-style:normal;font-weight:400;line-height:1.2">Book a free consultation call</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center"} -->\n<div class="wp-block-column is-vertically-aligned-center"><!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} -->\n<div class="wp-block-buttons"><!-- wp:button {"width":50,"style":{"color":{"background":"#fd6036"},"typography":{"fontSize":"15px","fontStyle":"normal","fontWeight":"600","lineHeight":"1.5"}}} -->\n<div class="wp-block-button has-custom-width wp-block-button__width-50 has-custom-font-size" style="font-size:15px;font-style:normal;font-weight:600;line-height:1.5"><a class="wp-block-button__link has-background wp-element-button" href="https://calendar.google.com/calendar/u/0/appointments/schedules/AcZssZ2YH5O0vNfBKX3do9Qr3aMnCS4xMBWdHds3dsI7Gd0_MKXldqSW5npKi5Sttdn0K9xAjNM0g-6L?gv=true&amp;pli=1" style="background-color:#fd6036" target="_blank" rel="noreferrer noopener">Free seo consultation -&gt;</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->', 'About Page', '', 'publish', 'closed', 'closed', '', 'about-page', '', '', '2024-01-14 14:11:26', '2024-01-14 14:11:26', '', 0, 'https://ccoms.ph/uncategorized/about-page/', 0, 'wp_template_part', '', 0),
