nDesktop":"row","directionTablet":"row","directionMobile":"column","justifyContentDesktop":"space-evenly","variationSelected":true,"rowGapMobile":38} -->\n<div class="wp-block-uagb-container uagb-block-88dfced7"><!-- wp:uagb/container {"block_id":"567d6de1","widthDesktop":50,"rowGapDesktop":10,"widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-567d6de1"><!-- wp:uagb/advanced-heading {"block_id":"92154b5d","classMigrate":true,"blockBackground":"","headingColor":"#333333","headFontFamily":"Sora","headFontWeight":"500","headTransform":"uppercase","headLineHeightType":"px","headFontSize":10,"headLineHeight":20,"headLetterSpacing":3,"headLoadGoogleFonts":true} -->\n<div class="wp-block-uagb-advanced-heading uagb-block-92154b5d"><h2 class="uagb-heading-text">what we do</h2></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:uagb/advanced-heading {"block_id":"bf3fa91c","classMigrate":true,"blockBackground":"","headingColor":"","headingTag":"h3","headFontFamily":"Sora","headFontWeight":"600","headTransform":"capitalize","headLineHeightType":"px","headFontSize":23,"headLineHeight":49,"headLoadGoogleFonts":true} -->\n<div class="wp-block-uagb-advanced-heading uagb-block-bf3fa91c"><h3 class="uagb-heading-text">How we do SEO strategies</h3></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:image {"id":188,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://ccoms.ph/wp-content/uploads/2024/01/How-we-do-SEO-strategies-01-1024x585.jpg" alt="" class="wp-image-188"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontStyle":"normal","fontWeight":"200","letterSpacing":"0.3px"}},"fontSize":"normal","fontFamily":"sora"} -->\n<p class="has-sora-font-family has-normal-font-size" style="font-style:normal;font-weight:200;letter-spacing:0.3px">Leveraging over ten years of SEO mastery, we tailor strategies to your business goals. Our advanced NLP and SEO tools fine-tune your web presence and Google Business Profile, boosting visibility and establishing your market authority. Expect meticulously planned and executed SEO, enhancing your brand with precision and care.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:uagb/container -->\n\n<!-- wp:uagb/container {"block_id":"064ac4cd","widthDesktop":40,"widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-064ac4cd"><!-- wp:uagb/faq {"block_id":"14ac436f","expandFirstItem":false,"enableSeparator":true,"rowsGap":30,"borderStyle":"","borderWidth":"","borderRadius":"","borderColor":"","questionTextColor":"#000000","answerTextColor":"#333333","questionloadGoogleFonts":true,"answerloadGoogleFonts":true,"questionFontFamily":"Sora","questionFontWeight":"600","questionTransform":"none","questionFontSize":16,"questionLineHeight":25,"questionLineHeightType":"px","answerFontFamily":"Sora","answerFontWeight":"300","answerTransform":"none","answerFontSize":14,"answerLineHeight":25,"answerLineHeightType":"px","icon":"angle-down","iconActive":"angle-up","iconAlign":"row-reverse","headingTag":"h3","overallBorderTopWidth":0,"overallBorderLeftWidth":0,"overallBorderRightWidth":0,"overallBorderBottomWidth":1,"overallBorderTopLeftRadius":2,"overallBorderTopRightRadius":2,"overallBorderBottomLeftRadius":2,"overallBorderBottomRightRadius":2,"overallBorderLink":false,"overallBorderStyle":"solid","overallBorderColor":"#D2D2D2","questionLetterSpacing":0} -->\n<div class="wp-block-uagb-faq uagb-faq__outer-wrap uagb-block-14ac436f uagb-faq-icon-row-reverse uagb-faq-layout-accordion uagb-faq-expand-first-false uagb-faq-inactive-other-true uagb-faq__wrap uagb-buttons-layout-wrap uagb-faq-equal-height" data-faqtoggle="true" role="tablist"><!-- wp:uagb/faq-child {"block_id":"e4d4e5c9","question":"Keyword Research","answer":"Unlock your market’s desires with our precision keyword research. We dig deep to find the search terms that will drive the most relevant traffic to your business, setting the foundation for all SEO efforts.","icon":"angle-down","iconActive":"angle-up","headingTag":"h3"} -->\n<div class="wp-block-uagb-faq-child uagb-faq-child__outer-wrap uagb-faq-item uagb-block-e4d4e5c9" role="tab" tabindex="0"><div class="uagb-faq-questions-button uagb-faq-questions"><span class="uagb-icon uagb-faq-icon-wrap"><svg xmlns="https://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="M192 384c-8.188 0-16.38-3.125-22.62-9.375l-160-160c-12.5-12.5-12.5-32.75 0-45.25s32.75-12.5 45.25 0L192 306.8l137.4-137.4c12.5-12.5 32.75-12.5 45.25 0s12.5 32.75 0 45.25l-160 160C208.4 380.9 200.2 384 192 384z"></path></svg></span><span class="uagb-icon-active uagb-faq-icon-wrap"><svg xmlns="https://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="M352 352c-8.188 0-16.38-3.125-22.62-9.375L192 205.3l-137.4 137.4c-12.5 12.5-32.75 12.5-45.25 0s-12.5-32.75 0-45.25l160-160c12.5-12.5 32.75-12.5 45.25 0l160 160c12.5 12.5 12.5 32.75 0 45.25C368.4 348.9 360.2 352 352 352z"></path></svg></span><h3 class="uagb-question">Keyword Research</h3></div><div class="uagb-faq-content"><p>Unlock your market’s desires with our precision keyword research. We dig deep to find the search terms that will drive the most relevant traffic to your business, setting the foundation for all SEO efforts.</p></div></div>\n<!-- /wp:uagb/faq-child -->\n\n<!-- wp:uagb/faq-child {"block_id":"541e7672","question":"Onsite Optimization","answer":"Fine-tune your website’s potential with our meticulous onsite optimization. We ensure every page speaks the language of success for search engines, enhancing user experience and SERP rankings.","icon":"angle-down","iconActive":"angle-up","headingTag":"h3"} -->\n<div class="wp-block-uagb-faq-child uagb-faq-child__outer-wrap uagb-faq-item uagb-block-541e7672" role="tab" tabindex="0"><div class="uagb-faq-questions-button uagb-faq-questions"><span class="uagb-icon uagb-faq-icon-wrap"><svg xmlns="https://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="M192 384c-8.188 0-16.38-3.125-22.62-9.375l-160-160c-12.5-12.5-12.5-32.75 0-45.25s32.75-12.5 45.25 0L192 306.8l137.4-137.4c12.5-12.5 32.75-12.5 45.25 0s12.5 32.75 0 45.25l-160 160C208.4 380.9 200.2 384 192 384z"></path></svg></span><span class="uagb-icon-active uagb-faq-icon-wrap"><svg xmlns="https://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="M352 352c-8.188 0-16.38-3.125-22.62-9.375L192 205.3l-137.4 137.4c-12.5 12.5-32.75 12.5-45.25 0s-12.5-32.75 0-45.25l160-160c12.5-12.5 32.75-12.5 45.25 0l160 160c12.5 12.5 12.5 32.75 0 45.25C368.4 348.9 360.2 352 352 352z"></path></svg></span><h3 class="uagb-question">Onsite Optimization</h3></div><div class="uagb-faq-content"><p>Fine-tune your website’s potential with our meticulous onsite optimization. We ensure every page speaks the language of success for search engines, enhancing user experience and SERP rankings.</p></div></div>\n<!-- /wp:uagb/faq-child -->\n\n<!-- wp:uagb/faq-child {"block_id":"541e7672","question":"Content Marketing with a Local Focus","answer":"Elevate your brand voice with content that resonates locally. Our strategic content marketing captures the essence of your community, turning local insights into customer engagements.","icon":"angle-down","iconActive":"angle-up","headingTag":"h3"} -->\n<div class="wp-block-uagb-faq-child uagb-faq-child__outer-wrap uagb-faq-item uagb-block-541e7672" role="tab" tabindex="0"><div class="uagb-faq-questions-button uagb-faq-questions"><span class="uagb-icon uagb-faq-icon-wrap"><svg xmlns="https://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="M192 384c-8.188 0-16.38-3.125-22.62-9.375l-160-160c-12.5-12.5-12.5-32.75 0-45.25s32.75-12.5 45.25 0L192 306.8l137.4-137.4c12.5-12.5 32.75-12.5 45.25 0s12.5 32.75 0 45.25l-160 160C208.4 380.9 200.2 384 192 384z"></path></svg></span><span class="uagb-icon-active uagb-faq-icon-wrap"><svg xmlns="https://www.w3.org/2000/svg" viewBox="0 0 384 512"><path d="M352 352c-8.188 0-16.38-3.125-22.62-9.375L192 205.3l-137.4 137.4c-12.5 12.5-32.75 12.5-45.25 0s-12.5-32.75