(386, 1, '2024-01-14 14:58:35', '2024-01-14 14:58:35', '<label> Your name\n    [text* your-name autocomplete:name] </label>\n\n<label> Your email\n    [email* your-email autocomplete:email] </label>\n\n<label> Subject\n    [text* your-subject] </label>\n\n<label> Your message (optional)\n    [textarea your-message] </label>\n\n[submit "Submit"]\n[_site_title] "[your-subject]"\n[_site_title] <wordpress@staging.core-conversion.com>\nFrom: [your-name] [your-email]\nSubject: [your-subject]\n\nMessage Body:\n[your-message]\n\n-- \nThis is a notification that a contact form was submitted on your website ([_site_title] [_site_url]).\n[_site_admin_email]\nReply-To: [your-email]\n\n0\n0\n\n[_site_title] "[your-subject]"\n[_site_title] <wordpress@staging.core-conversion.com>\nMessage Body:\n[your-message]\n\n-- \nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\n[your-email]\nReply-To: [_site_admin_email]\n\n0\n0\nThank you for your message. It has been sent.\nThere was an error trying to send your message. Please try again later.\nOne or more fields have an error. Please check and try again.\nThere was an error trying to send your message. Please try again later.\nYou must accept the terms and conditions before sending your message.\nPlease fill out this field.\nThis field has a too long input.\nThis field has a too short input.\nThere was an unknown error uploading the file.\nYou are not allowed to upload files of this type.\nThe uploaded file is too large.\nThere was an error uploading the file.', 'Contact form 1', '', 'publish', 'closed', 'closed', '', 'contact-form-1', '', '', '2024-01-14 14:58:35', '2024-01-14 14:58:35', '', 0, 'https://ccoms.ph/?post_type=wpcf7_contact_form&p=386', 0, 'wpcf7_contact_form', '', 0),
(388, 1, '2024-01-14 15:03:57', '2024-01-14 15:03:57', '<div class="row">\r\n    <div class="column">\r\n        <label>Your First Name (required)\r\n            [text* first-name placeholder "First Name"]\r\n        </label>\r\n    </div>\r\n    <div class="column">\r\n        <label>Your Last Name (required)\r\n            [text* last-name placeholder "Last Name"]\r\n        </label>\r\n    </div>\r\n</div>\r\n\r\n<label>Your Email (required)\r\n    [email* your-email placeholder "Email Address"]\r\n</label>\r\n\r\n<label>Subject\r\n    [text* your-subject]\r\n</label>\r\n\r\n<label>Your Message (optional)\r\n    [textarea your-message placeholder "Message"]\r\n</label>\r\n\r\n[submit "Submit"]\n1\n[_site_title] "[your-subject]"\n[_site_title] <wordpress@staging.core-conversion.com>\n[_site_admin_email]\nFrom: [your-name] [your-email]\r\nSubject: [your-subject]\r\n\r\nMessage Body:\r\n[your-message]\r\n\r\n-- \r\nThis is a notification that a contact form was submitted on your website ([_site_title] [_site_url]).\nReply-To: [your-email]\n\n\n\n\n[_site_title] "[your-subject]"\n[_site_title] <wordpress@staging.core-conversion.com>\n[your-email]\nMessage Body:\r\n[your-message]\r\n\r\n-- \r\nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\nReply-To: [_site_admin_email]\n\n\n\nThank you for your message. It has been sent.\nThere was an error trying to send your message. Please try again later.\nOne or more fields have an error. Please check and try again.\nThere was an error trying to send your message. Please try again later.\nYou must accept the terms and conditions before sending your message.\nPlease fill out this field.\nThis field has a too long input.\nThis field has a too short input.\nThere was an unknown error uploading the file.\nYou are not allowed to upload files of this type.\nThe uploaded file is too large.\nThere was an error uploading the file.\nPlease enter a date in YYYY-MM-DD format.\nThis field has a too early date.\nThis field has a too late date.\nPlease enter a number.\nThis field has a too small number.\nThis field has a too large number.\nThe answer to the quiz is incorrect.\nPlease enter an email address.\nPlease enter a URL.\nPlease enter a telephone number.', 'Contact form Page', '', 'publish', 'closed', 'closed', '', 'contact-form-page', '', '', '2024-01-14 15:03:57', '2024-01-14 15:03:57', '', 0, 'https://ccoms.ph/?post_type=wpcf7_contact_form&p=388', 0, 'wpcf7_contact_form', '', 0),
(391, 1, '2024-01-15 19:21:06', '2024-01-15 19:21:06', '/* Contact Form 7 Styles with !important */\r\n.wpcf7-form {\r\n    max-width: 500px !important;\r\n    margin: auto !important;\r\n    background: #f7f7f7 !important;\r\n    padding: 20px !important;\r\n    border-radius: 8px !important;\r\n    box-shadow: 0 4px 8px rgba(0,0,0,0.1) !important;\r\n}\r\n\r\n.wpcf7 input[type="text"],\r\n.wpcf7 input[type="email"],\r\n.wpcf7 textarea {\r\n    width: 100% !important;\r\n    padding: 10px !important;\r\n    margin: 5px 0 20px 0 !important;\r\n    border: 1px solid #ccc !important;\r\n    border-radius: 4px !important;\r\n    box-sizing: border-box !important; /* Ensures padding doesn''t affect width */\r\n}\r\n\r\n.wpcf7 input[type="text"]:focus,\r\n.wpcf7 input[type="email"]:focus,\r\n.wpcf7 textarea:focus {\r\n    outline: none !important;\r\n    border-color: #007bff !important;\r\n}\r\n\r\n.wpcf7 input[type="submit"] {\r\n    width: 100% !important;\r\n    padding: 10px !important;\r\n    border: none !important;\r\n    border-radius: 4px !important;\r\n    color: white !important;\r\n    background-color: #007bff !important;\r\n    cursor: pointer !important;\r\n    font-size: 16px !important;\r\n    transition: background-color 0.3s !important; /* Smooth background color transition */\r\n}\r\n\r\n.wpcf7 input[type="submit"]:hover {\r\n    background-color: #0056b3 !important;\r\n}\r\n\r\n.wpcf7 label {\r\n    display: block !important;\r\n    margin-bottom: .5rem !important;\r\n    font-weight: bold !important;\r\n}\r\n\r\n.wpcf7-response-output {\r\n    margin: 2em 0.5em 1em !important;\r\n    padding: 0.2em 1em !important;\r\n    border: 2px solid #ff0000 !important;\r\n    border-radius: 10px !important;\r\n}\r\n', 'CF7', '', 'publish', 'closed', 'closed', '', 'cf7', '', '', '2024-01-15 19:21:06', '2024-01-15 19:21:06', '', 0, 'https://ccoms.ph/?post_type=custom-css-js&#038;p=391', 0, 'custom-css-js', '', 0);
