(1122, 1, '2024-01-29 16:06:41', '2024-01-29 08:06:41', '<!-- wp:template-part {"slug":"header-transparent-copy","theme":"blockstarter","area":"header"} /-->\n\n<!-- wp:uagb/container {"block_id":"5541489e","topMarginDesktop":0,"bottomMarginDesktop":100,"leftMarginDesktop":0,"rightMarginDesktop":0,"marginLink":false,"variationSelected":true,"isBlockRootParent":true} -->\n<div class="wp-block-uagb-container uagb-block-5541489e alignfull uagb-is-root-container"><div class="uagb-container-inner-blocks-wrap"><!-- wp:uagb/container {"block_id":"c179e997","innerContentCustomWidthDesktop":1119,"minHeightDesktop":350,"directionDesktop":"row","alignItemsDesktop":"flex-start","justifyContentDesktop":"space-evenly","topPaddingDesktop":0,"paddingLink":false,"topMarginDesktop":100,"bottomMarginDesktop":100,"leftMarginDesktop":0,"rightMarginDesktop":0,"marginLink":false,"variationSelected":true,"isBlockRootParent":true,"childrenWidthDesktop":"auto"} -->\n<div class="wp-block-uagb-container uagb-block-c179e997 alignfull uagb-is-root-container"><div class="uagb-container-inner-blocks-wrap"><!-- wp:uagb/container {"block_id":"43feae2e","widthDesktop":40,"alignItemsDesktop":"flex-start","widthSetByUser":true} -->\n<div class="wp-block-uagb-container uagb-block-43feae2e"><!-- wp:uagb/advanced-heading {"block_id":"a166fa2f","classMigrate":true,"headingColor":"#333333","headFontFamily":"Sora","headFontSize":36,"headLoadGoogleFonts":true} -->\n<div class="wp-block-uagb-advanced-heading uagb-block-a166fa2f"><h2 class="uagb-heading-text">Welcome to the blog! I''m Paul Carrasco</h2></div>\n<!-- /wp:uagb/advanced-heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontStyle":"normal","fontWeight":"200","fontSize":"19px"}},"fontFamily":"sora"} -->\n<p class="has-sora-font-family" style="font-size:19px;font-style:normal;font-weight:200">With a decade of SEO expertise under my belt, I''ve assisted countless businesses in navigating the complexities of digital growth, from improving rankings to boosting leads. This blog is my platform to pass on that wealth of knowledge to you. Here, you''ll find comprehensive guides and actionable advice designed to enhance your local business''s online visibility and performance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontStyle":"normal","fontWeight":"200","fontSize":"19px"}},"fontFamily":"sora"} -->\n<p class="has-sora-font-family" style="font-size:19px;font-style:normal;font-weight:200"><strong>Ready for a deeper dive into Local SEO? Subscribe to my newsletter for tailored tips and insights.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:uagb/container {"block_id":"5e6a0e3a","widthDesktop":80,"justifyContentDesktop":"flex-end","widthSetByUser":true,"childrenWidthDesktop":"equal"} -->\n<div class="wp-block-uagb-container uagb-block-5e6a0e3a"><!-- wp:uagb/forms {"block_id":"c8430b33","buttonAlign":"full","confirmationMessage":"Thank you for subscribing! You''ve taken a great step towards unlocking your local business''s potential. Keep an eye on your inbox for expert Local SEO tips and insights.","afterSubmitToEmail":"newsletter@core-conversion.com","afterSubmitEmailSubject":"Email Subscriber","submitBgColor":"#0099ff","submitborderRadius":"","inputloadGoogleFonts":true,"inputFontFamily":"Sora","inputFontWeight":"200","inputFontSize":18,"inputColor":"#333333","inputborderStyle":"","inputborderWidth":"","inputborderRadius":"","inputborderColor":"","reCaptchaEnable":true,"reCaptchaType":"v3","hidereCaptchaBatch":true,"inputTransform":"none","displayLabels":false,"fieldBorderTopWidth":1,"fieldBorderLeftWidth":1,"fieldBorderRightWidth":1,"fieldBorderBottomWidth":1,"fieldBorderTopLeftRadius":15,"fieldBorderTopRightRadius":15,"fieldBorderBottomLeftRadius":15,"fieldBorderBottomRightRadius":15,"fieldBorderStyle":"solid","fieldBorderColor":"rgba(189,189,189,0.42)","checkBoxToggleBorderTopWidth":1,"checkBoxToggleBorderLeftWidth":1,"checkBoxToggleBorderRightWidth":1,"checkBoxToggleBorderBot